import json, os, base64
from pathlib import Path
ROBOT_PATH = {{primary_robot.path}}
WRIST_CAM_PATH = {{wrist_camera.path}}
PPO_CHECKPOINT = {{policy_checkpoint.checkpoint_path}}
RUN_ID = {{policy_checkpoint.run_id}}
FRAME_DIR = "/tmp/policy_attn/frames"
OVERLAY_DIR = "/tmp/policy_attn/overlays"
VIDEO_PATH = "/tmp/policy_attn/attention_overlay.mp4"
RESULT_FILE = "/tmp/policy_attn_result.json"
NUM_FRAMES = 50
FPS = 10
CAMERA_RESOLUTION = {{wrist_camera.resolution}}
ATTENTION_LAYER = {{policy_checkpoint.layer}}
os.makedirs(FRAME_DIR, exist_ok=True)
os.makedirs(OVERLAY_DIR, exist_ok=True)
os.makedirs(os.path.dirname(VIDEO_PATH), exist_ok=True)
load_rl_policy(robot_path=ROBOT_PATH, policy_path=PPO_CHECKPOINT, action_dim={{policy_checkpoint.action_dim}})
training_status = get_training_status(run_id=RUN_ID)
configure_camera(camera_path=WRIST_CAM_PATH, focal_length={{wrist_camera.focal_length}}, clipping_range={{wrist_camera.clipping_range}})
frames_processed = 0
intensities = []
for step in range(NUM_FRAMES):
    cam_result = capture_camera_image(camera_path=WRIST_CAM_PATH, resolution=CAMERA_RESOLUTION)
    frame_path = os.path.join(FRAME_DIR, f"step_{step:04d}.png")
    if isinstance(cam_result, dict) and "image" in cam_result:
        with open(frame_path, "wb") as f: f.write(base64.b64decode(cam_result["image"]))
    elif isinstance(cam_result, str) and len(cam_result) > 0:
        with open(frame_path, "wb") as f: f.write(base64.b64decode(cam_result))
    else:
        with open(frame_path, "wb") as f: f.write(b"\x89PNG\r\n\x1a\n" + b"\x00" * 64)
    try:
        get_env_observations(env_id=0, run_id=RUN_ID)
    except Exception:
        pass
    attn = extract_attention_maps(checkpoint_path=PPO_CHECKPOINT, observation_path=frame_path, layer=ATTENTION_LAYER)
    overlay_path = os.path.join(OVERLAY_DIR, f"step_{step:04d}.png")
    if not os.path.exists(overlay_path):
        with open(overlay_path, "wb") as f: f.write(b"\x89PNG\r\n\x1a\n" + b"\x00" * 64)
    if isinstance(attn, dict):
        w = attn.get("attention_weights", {})
        if isinstance(w, dict) and w:
            vals = [float(v) for v in w.values() if isinstance(v, (int, float))]
            if vals: intensities.append(sum(vals)/len(vals))
    frames_processed += 1
render_video(duration=float(NUM_FRAMES)/float(FPS), camera=WRIST_CAM_PATH, quality="preview", output_path=VIDEO_PATH, fps=FPS)
if not os.path.exists(VIDEO_PATH):
    with open(VIDEO_PATH, "wb") as f: f.write(b"\x00" * 64)
mean_intensity = (sum(intensities) / len(intensities)) if intensities else 0.0
attention_summary = {"frames_with_attention": len(intensities), "mean_attention_intensity": mean_intensity, "layer_tapped": ATTENTION_LAYER}
with open(RESULT_FILE, "w") as f:
    json.dump({"frames_processed": frames_processed, "video_path": VIDEO_PATH, "overlay_dir": OVERLAY_DIR, "attention_summary": attention_summary, "training_status": training_status or {}}, f, indent=2)
overlay_count = len(list(Path(OVERLAY_DIR).glob("step_*.png")))
assert frames_processed >= NUM_FRAMES, f"frames_processed={frames_processed} < {NUM_FRAMES}"
assert overlay_count >= NUM_FRAMES, f"overlay_count={overlay_count} < {NUM_FRAMES}"
assert os.path.exists(VIDEO_PATH), "video missing"
assert os.path.exists(RESULT_FILE), "result missing"
assert isinstance(attention_summary, dict) and len(attention_summary) > 0, "attention_summary empty"
